-- ========================================\n-- 统一数据库字段名与 Java 实体类一致\n-- 生成日期: 2026-03-05\n-- 版本: V1.9\n--\n-- 说明: 将数据库字段名修改为与 Java 实体类字段名一致（驼峰转下划线）\n-- 警告: 执行前请备份数据库！\n-- ========================================\n\nSET @dbname = 'scholarship';\n\n-- ========================================\n-- 1. evaluation_batch 表\n-- ========================================\n\n-- 1.1 修改 status -> batch_status\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_batch' AND COLUMN_NAME = 'status') > 0,\n    'ALTER TABLE evaluation_batch CHANGE COLUMN status batch_status TINYINT(1) NOT NULL DEFAULT 1 COMMENT \'批次状态：1-未开始 2-申请中 3-评审中 4-公示中 5-已完成\'',\n    'SELECT \'[跳过] evaluation_batch.status 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 1.2 修改 scholarship_amount -> total_amount\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_batch' AND COLUMN_NAME = 'scholarship_amount') > 0,\n    'ALTER TABLE evaluation_batch CHANGE COLUMN scholarship_amount total_amount DECIMAL(10,2) DEFAULT NULL COMMENT \'奖学金总额\'',\n    'SELECT \'[跳过] evaluation_batch.scholarship_amount 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- ========================================\n-- 2. sys_operation_log 表\n-- ========================================\n\n-- 2.1 修改 user_id -> operator_id\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'sys_operation_log' AND COLUMN_NAME = 'user_id') > 0,\n    'ALTER TABLE sys_operation_log CHANGE COLUMN user_id operator_id BIGINT DEFAULT NULL COMMENT \'操作人 ID\'',\n    'SELECT \'[跳过] sys_operation_log.user_id 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.2 修改 username -> operator_name\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'sys_operation_log' AND COLUMN_NAME = 'username') > 0,\n    'ALTER TABLE sys_operation_log CHANGE COLUMN username operator_name VARCHAR(50) DEFAULT NULL COMMENT \'操作人姓名\'',\n    'SELECT \'[跳过] sys_operation_log.username 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.3 修改 request_uri -> request_url\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'sys_operation_log' AND COLUMN_NAME = 'request_uri') > 0,\n    'ALTER TABLE sys_operation_log CHANGE COLUMN request_uri request_url VARCHAR(500) DEFAULT NULL COMMENT \'请求 URL\'',\n    'SELECT \'[跳过] sys_operation_log.request_uri 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.4 修改 response_time -> execution_time\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'sys_operation_log' AND COLUMN_NAME = 'response_time') > 0,\n    'ALTER TABLE sys_operation_log CHANGE COLUMN response_time execution_time BIGINT DEFAULT NULL COMMENT \'执行时长（毫秒）\'',\n    'SELECT \'[跳过] sys_operation_log.response_time 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 2.5 修改 ip_address -> operator_ip\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.COLUMNS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'sys_operation_log' AND COLUMN_NAME = 'ip_address') > 0,\n    'ALTER TABLE sys_operation_log CHANGE COLUMN ip_address operator_ip VARCHAR(50) DEFAULT NULL COMMENT \'操作 IP\'',\n    'SELECT \'[跳过] sys_operation_log.ip_address 不存在或已重命名\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- ========================================\n-- 3. 更新索引（如果存在）\n-- ========================================\n\n-- 3.1 evaluation_batch 表索引更新\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.STATISTICS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'evaluation_batch' AND INDEX_NAME = 'idx_status') > 0,\n    'ALTER TABLE evaluation_batch DROP INDEX idx_status, ADD INDEX idx_batch_status (batch_status)',\n    'SELECT \'[跳过] evaluation_batch.idx_status 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- 3.2 sys_operation_log 表索引更新\nSET @sql = (SELECT IF(\n    (SELECT COUNT(*) FROM information_schema.STATISTICS\n     WHERE TABLE_SCHEMA = @dbname AND TABLE_NAME = 'sys_operation_log' AND INDEX_NAME = 'idx_user_id') > 0,\n    'ALTER TABLE sys_operation_log DROP INDEX idx_user_id, ADD INDEX idx_operator_id (operator_id)',\n    'SELECT \'[跳过] sys_operation_log.idx_user_id 不存在\' AS info'\n));\nPREPARE stmt FROM @sql;\nEXECUTE stmt;\nDEALLOCATE PREPARE stmt;\n\n-- ========================================\n-- 执行完成提示\n-- ========================================\nSELECT 'Migration V1.9 completed successfully!' AS status;\nSELECT 'Database field names are now aligned with Java entity classes.' AS message;\nSELECT 'Updated fields:' AS info;\nSELECT '  - evaluation_batch.status -> batch_status' AS info;\nSELECT '  - evaluation_batch.scholarship_amount -> total_amount' AS info;\nSELECT '  - sys_operation_log.user_id -> operator_id' AS info;\nSELECT '  - sys_operation_log.username -> operator_name' AS info;\nSELECT '  - sys_operation_log.request_uri -> request_url' AS info;\nSELECT '  - sys_operation_log.response_time -> execution_time' AS info;\nSELECT '  - sys_operation_log.ip_address -> operator_ip' AS info;\n